targets.expr:
sum by (node, pod_id) (
  label_replace(
    label_replace(
      rate(container_cpu_usage_seconds_total{id=~"/kubepods.slice/.*", cpu="total"}[1m]),
      "pod_id", "$1", "id", ".*/pod([^/]+).*"
    ),
    "node", "$1", "instance", "(.*)"
  )
)

sum by (node, service_name) (
  label_replace(
    label_replace(
      rate(container_cpu_usage_seconds_total{
        id=~"/system.slice/.*\\.service", 
        instance=~"$Node"
      }[1m]),
      "service_name", "$1", "id", ".*/(.*)\\.service"
    ),
    "node", "$1", "instance", "(.*)"
  )
)

sum by (node, pod_id) (
  label_replace(
    label_replace(
      container_memory_working_set_bytes{
        id=~"/kubepods.slice/.*", 
        instance=~"$Node"
      },
      "pod_id", "$1", "id", ".*/pod([^/]+).*"
    ),
    "node", "$1", "instance", "(.*)"
  )
)

sum by (instance, service_name) (
  label_replace(
    container_memory_working_set_bytes{
      id=~"/system.slice/.*\\.service", 
      instance=~"$Node"
    },
    "service_name", "$1", "id", ".*/(.*)\\.service"
  )
)
